import React, { useState, useEffect } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, ShoppingCart, LogOut } from 'lucide-react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 }; 

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [distanciaReal, setDistanciaReal] = useState(0);
  const [verCarrito, setVerCarrito] = useState(false);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const agrupado = {};
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      if (ofs.length > 0) agrupado[l.nombre] = ofs.map(o => ({ ...o, nombreLocal: l.nombre }));
    });
    setOfertasPorLocal(agrupado);
    setPedidos(JSON.parse(localStorage.getItem('historial-pedidos') || "[]"));
  }, []);

  const handleLogout = () => { window.location.href = "/"; };

  return (
    <div style={panelLayout}>
      {/* HEADER FIJO */}
      <header style={headerStyle}>
        <div style={logoStyle}>OFERTAS<span style={{color: '#e67e22'}}>APP</span></div>
        <div style={userActions}>
          <span style={userGreeting}>Hola, <strong style={{color: '#e67e22'}}>Panche</strong></span>
          <button onClick={handleLogout} style={btnLogout}>
            <LogOut size={20} />
          </button>
        </div>
      </header>

      {/* CONTENEDOR INFERIOR (Sidebar + Main) */}
      <div style={bodyWrapper}>
        {/* SIDEBAR FIJA */}
        <aside style={sidebar}>
          <nav style={navStyle}>
            <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? btnNavActive : btnNav}>
              <ShoppingBag size={20}/> Hacer mi pedido
            </button>
            <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? btnNavActive : btnNav}>
              <ShoppingCart size={20}/> Mi carrito ({cart.length})
            </button>
            <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? btnNavActive : btnNav}>
              <Clock size={20}/> En Proceso
            </button>
            <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? btnNavActive : btnNav}>
              <CheckCircle size={20}/> Historial
            </button>
          </nav>
        </aside>

        {/* CONTENIDO SCROLLEABLE */}
        <main style={mainContent}>
          {tab === 'tienda' && !verCarrito && (
            <>
              <div style={searchBar}>
                <MapPin size={20} color="#e67e22" />
                <input style={input} placeholder="¿A dónde enviamos hoy?" value={busqueda} onChange={(e) => setBusqueda(e.target.value)} />
              </div>

              {Object.keys(ofertasPorLocal).map(nombreLocal => (
                <div key={nombreLocal} style={localSection}>
                  <h3 style={localTitle}>{nombreLocal}</h3>
                  <div style={horizontalScroll}>
                    {ofertasPorLocal[nombreLocal].map(o => (
                      <div key={o.id} style={cardOferta}>
                        <img src={o.imagen} style={imgStyle} alt={o.producto} />
                        <div style={{padding: '12px'}}>
                          <h4 style={{margin: '0 0 10px 0', fontSize: '1rem'}}>{o.producto}</h4>
                          <button style={btnAdd} onClick={() => setCart([...cart, o])}>
                            Agregar ${o.precioNuevo}
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </>
          )}

          {verCarrito && (
            <div style={carritoContainer}>
              <h2 style={{marginBottom: '20px'}}>Resumen de Compra</h2>
              <Carrito cart={cart} setCart={setCart} distanciaReal={distanciaReal} onCheckout={() => setTab('proceso')} />
            </div>
          )}

          {tab === 'proceso' && (
            <div style={centeredContainer}>
              <h2 style={{marginBottom: '20px'}}>Seguimiento</h2>
              {pedidos.filter(p => p.estado === 'proceso').map(p => (
                <SeguimientoPedido key={p.id} pedido={p} onFinalizar={() => {}} />
              ))}
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

// --- ESTILOS REPARADOS (Sin barras extras) ---
const panelLayout = { 
  height: '100vh', 
  display: 'flex', 
  flexDirection: 'column', 
  overflow: 'hidden', // Evita el scroll global de la página
  background: '#f4f7f9' 
};

const headerStyle = { 
  height: '70px', minHeight: '70px', background: '#1a202c', 
  display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
  padding: '0 40px', zIndex: 1000, borderBottom: '1px solid #2d3748'
};

const bodyWrapper = { 
  display: 'flex', 
  flex: 1, 
  overflow: 'hidden' // Importante para que el scroll solo sea en el main
};

const sidebar = { 
  width: '260px', background: '#1a202c', 
  display: 'flex', flexDirection: 'column'
};

const mainContent = { 
  flex: 1, 
  padding: '40px', 
  overflowY: 'auto', // Solo el contenido de las ofertas tendrá scroll
  background: '#f4f7f9' 
};

// --- RESTO DE ESTILOS ---
const logoStyle = { color: 'white', fontSize: '1.5rem', fontWeight: 'bold' };
const userActions = { display: 'flex', alignItems: 'center', gap: '20px' };
const userGreeting = { color: 'white', fontSize: '0.9rem' };
const btnLogout = { background: 'none', border: 'none', color: '#cbd5e1', cursor: 'pointer' };
const navStyle = { display: 'flex', flexDirection: 'column', gap: '8px', padding: '20px' };
const btnNav = { display: 'flex', alignItems: 'center', gap: '12px', padding: '14px', background: 'none', border: 'none', color: '#a0aec0', cursor: 'pointer', borderRadius: '12px', textAlign: 'left', width: '100%' };
const btnNavActive = { ...btnNav, background: '#e67e22', color: 'white' };
const localSection = { marginBottom: '40px' };
const localTitle = { fontSize: '1.3rem', color: '#2d3748', marginBottom: '15px', borderLeft: '5px solid #e67e22', paddingLeft: '15px' };
const horizontalScroll = { display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '15px' };
const cardOferta = { minWidth: '220px', background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden' };
const imgStyle = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAdd = { width: '100%', padding: '10px', background: '#1a202c', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };
const searchBar = { display: 'flex', alignItems: 'center', background: 'white', padding: '15px 25px', borderRadius: '12px', marginBottom: '35px' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px' };
const carritoContainer = { maxWidth: '600px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '20px' };
const centeredContainer = { maxWidth: '700px', margin: '0 auto' };

export default PanelCliente;
